import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import EmployeeLayout from '../components/EmployeeLayout';
import styles from './InventoryPage.module.css';
import sharedStyles from './PageStyle2.module.css';

function InventoryPage() {
  const [books, setBooks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    const fetchBooks = async () => {
      try {
        const userInfo = JSON.parse(localStorage.getItem('userInfo'));
        const config = {
          headers: {
            Authorization: `Bearer ${userInfo.token}`,
          },
        };
        const { data } = await axios.get('/api/books', config);
        setBooks(data);
      } catch (err) {
        setError(err.response?.data?.message || 'Failed to fetch inventory');
      } finally {
        setLoading(false);
      }
    };

    fetchBooks();
  }, []);

  const formatDate = (dateString) => {
    if (!dateString) return 'N/A';
    return new Date(dateString).toLocaleDateString();
  };

  if (loading) {
    return <EmployeeLayout title="Inventory"><div>Loading...</div></EmployeeLayout>;
  }

  return (
    <EmployeeLayout title="Inventory">
      <div style={{ marginBottom: '1.5rem', display: 'flex', justifyContent: 'flex-end' }}>
        <Link to="/insertbook" className={sharedStyles.menuItem} style={{ backgroundColor: '#004085', color: 'white' }}>
          Add New Book
        </Link>
      </div>
      {error && <p className={sharedStyles.error}>{error}</p>}
      <div className={styles.inventoryContainer}>
        {books.map((book) => (
          <Link to={`/editbook/${book._id}`}>
          <div key={book._id} className={styles.bookCard}>
            <div className={styles.coverArt}>
              <img src={book.coverArt || '/placeholder.png'} alt={`${book.seriesTitle} #${book.issueNumber}`} />
            </div>
            <div className={styles.bookDetails}>
              <h3>{book.seriesTitle} #{book.issueNumber}</h3>
              <p className={styles.detailItem}><strong>Publisher:</strong> {book.publisher || 'N/A'}</p>
              <p className={styles.detailItem}><strong>Release Date:</strong> {formatDate(book.releaseDate)}</p>
              <p className={styles.detailItem}><strong>Series Start:</strong> {formatDate(book.seriesStartDate)}</p>
              <p className={styles.detailItem}><strong>Series End:</strong> {formatDate(book.seriesEndDate)}</p>
              <div className={styles.tags}>
                {book.tags.map((tag, index) => <span key={index} className={styles.tag}>{tag}</span>)}
              </div>
              {/* <div className={styles.cardActions}>
                <Link to={`/editbook/${book._id}`} className={sharedStyles.menuItem} style={{ backgroundColor: '#004085', color: 'white' }}>Edit</Link>
              </div> */}
            </div>
          </div>
          </Link>
        ))}
      </div>
    </EmployeeLayout>
  );
}

export default InventoryPage;
